"use client"

import { Card } from "@/types/tcg"
import { formatManaCost, getCardPowerToughness } from "@/lib/data/cards"
import { cn } from "@/lib/utils"

interface GameStatsDisplayProps {
  card: Card
  oracleText?: string
  flavorText?: string
  legality?: Record<string, boolean>
  className?: string
}

interface StatRow {
  label: string
  value: React.ReactNode
}

const MTG_COLOR_MAP: Record<string, { name: string; color: string }> = {
  W: { name: "White", color: "#f5f5dc" },
  U: { name: "Blue", color: "#60a5fa" },
  B: { name: "Black", color: "#a1a1aa" },
  R: { name: "Red", color: "#ef4444" },
  G: { name: "Green", color: "#22c55e" },
}

export function GameStatsDisplay({ card, oracleText, flavorText, legality, className }: GameStatsDisplayProps) {
  const powerToughness = getCardPowerToughness(card)

  const getMTGStats = (): StatRow[] => {
    const rows: StatRow[] = []

    if (card.primaryType) {
      rows.push({ label: "Type", value: card.primaryType })
    }

    if (card.manaCost) {
      rows.push({
        label: "Mana Cost",
        value: <span className="font-mono tracking-wider">{formatManaCost(card)}</span>,
      })
    }

    if (card.manaValue !== undefined) {
      rows.push({ label: "Mana Value", value: card.manaValue })
    }

    if (powerToughness) {
      rows.push({
        label: "Power/Toughness",
        value: <span className="font-mono">{powerToughness}</span>,
      })
    }

    if (card.colors && card.colors.length > 0) {
      rows.push({
        label: "Colors",
        value: (
          <span className="flex items-center gap-1">
            {card.colors.map((c) => {
              const colorInfo = MTG_COLOR_MAP[c]
              return (
                <span key={c} style={{ color: colorInfo?.color }}>
                  {colorInfo?.name || c}
                </span>
              )
            })}
          </span>
        ),
      })
    }

    return rows
  }

  const getPokemonStats = (): StatRow[] => {
    const rows: StatRow[] = []

    if (card.hp) {
      rows.push({ label: "HP", value: card.hp })
    }

    if (card.energyTypes && card.energyTypes.length > 0) {
      rows.push({ label: "Energy Types", value: card.energyTypes.join(", ") })
    }

    if (card.retreatCost !== undefined) {
      rows.push({ label: "Retreat Cost", value: card.retreatCost })
    }

    if (card.evolutionStage) {
      rows.push({ label: "Evolution Stage", value: card.evolutionStage })
    }

    return rows
  }

  const getYuGiOhStats = (): StatRow[] => {
    const rows: StatRow[] = []

    if (card.attribute) {
      rows.push({ label: "Attribute", value: card.attribute })
    }

    if (card.levelRank !== undefined) {
      rows.push({ label: "Level/Rank", value: card.levelRank })
    }

    if (card.attackValue !== undefined && card.defenseValueYugioh !== undefined) {
      rows.push({
        label: "ATK/DEF",
        value: (
          <span className="font-mono">
            {card.attackValue}/{card.defenseValueYugioh}
          </span>
        ),
      })
    }

    return rows
  }

  const getOnePieceStats = (): StatRow[] => {
    const rows: StatRow[] = []

    if (card.cost !== undefined) {
      rows.push({ label: "Cost", value: card.cost })
    }

    if (card.power !== undefined) {
      rows.push({ label: "Power", value: card.power })
    }

    if (card.counterValue !== undefined) {
      rows.push({ label: "Counter", value: card.counterValue })
    }

    if (card.lifeValue !== undefined) {
      rows.push({ label: "Life", value: card.lifeValue })
    }

    return rows
  }

  const getStatsForGame = (): StatRow[] => {
    switch (card.game?.code) {
      case "MTG":
        return getMTGStats()
      case "POKEMON":
        return getPokemonStats()
      case "YUGIOH":
        return getYuGiOhStats()
      case "OPTCG":
        return getOnePieceStats()
      default:
        return []
    }
  }

  const stats = getStatsForGame()

  if (stats.length === 0) {
    return (
      <div className="bg-component-secondary rounded-lg p-6 text-center">
        <div className="w-12 h-12 mx-auto mb-3 bg-component-primary rounded-lg flex items-center justify-center">
          <svg className="w-5 h-5 text-secondary" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" />
          </svg>
        </div>
        <h3 className="heading-xs text-primary mb-1">No Game Stats</h3>
        <p className="text-sm text-secondary">
          This card has no game-specific statistics available.
        </p>
      </div>
    )
  }

  return (
    <div
      className={cn("overflow-hidden", className)}
      style={{
        background: "rgba(33, 32, 58, 0.6)",
        border: "0.667px solid #2c2a4a",
        borderRadius: 16,
      }}
    >
      <div className="flex items-center px-6 py-4" style={{ borderBottom: "1px solid rgba(44, 42, 74, 0.5)" }}>
        <span
          className="font-barlow font-semibold uppercase"
          style={{ fontSize: 14, letterSpacing: "0.84px", color: "var(--text-secondary, #B8B0D8)" }}
        >
          Card Details
        </span>
      </div>
      <dl>
        {stats.map((stat, idx) => (
          <div
            key={stat.label}
            className="flex items-center justify-between px-6 py-2.5"
            style={idx < stats.length - 1 ? { borderBottom: "1px solid rgba(44, 42, 74, 0.5)" } : undefined}
          >
            <dt className="font-medium" style={{ fontSize: 13, color: "#7b72a8" }}>{stat.label}</dt>
            <dd style={{ fontSize: 13, color: "#f0eeff" }}>{stat.value}</dd>
          </div>
        ))}
      </dl>

      {/* Oracle text */}
      {oracleText && (
        <div
          data-testid="oracle-text"
          className="mx-6 my-3 rounded-[10px] leading-relaxed"
          style={{
            padding: "12px 16px",
            fontSize: 14,
            background: "rgba(9, 9, 15, 0.4)",
            borderLeft: "3px solid var(--brand-primary, #8B5CF6)",
            color: "var(--text-primary, #F0EEFF)",
          }}
        >
          {oracleText}
        </div>
      )}

      {/* Flavor text */}
      {flavorText && (
        <div className="mx-6 mb-3" style={{ padding: "8px 16px" }}>
          <p className="italic" style={{ fontSize: 13, color: "#7b72a8" }}>{flavorText}</p>
        </div>
      )}

      {/* Format Legality */}
      {legality && Object.keys(legality).length > 0 && (
