          >
            Format Legality
          </span>
          <div className="flex flex-wrap gap-2 mt-2">
            {Object.entries(legality).map(([format, isLegal]) => (
              <span
                key={format}
                className="inline-flex items-center gap-1 px-3 py-1 rounded-full text-xs font-medium"
                style={{
                  color: isLegal ? "var(--positive, #10B981)" : "var(--negative, #EF4444)",
                  borderWidth: 1,
                  borderStyle: "solid",
                  borderColor: isLegal ? "rgba(16, 185, 129, 0.25)" : "rgba(239, 68, 68, 0.25)",
                  background: isLegal ? "rgba(16, 185, 129, 0.08)" : "rgba(239, 68, 68, 0.08)",
                }}
              >
                <span aria-hidden="true">{isLegal ? "\u2713" : "\u2717"}</span>
                {format}
              </span>
            ))}
          </div>
        </div>
      )}
    </div>
  )
}

