function isFoil(print: PrintWithPrice): boolean {
  return print.finish?.toUpperCase() !== "NORMAL" && !!print.finish
}

export function CompactPrintingsTable({
  prints,
  selectedPrint,
  currentPrintId,
  onPrintSelect,
  className,
}: CompactPrintingsTableProps) {
  const [showAll, setShowAll] = useState(false)

  if (!prints || prints.length === 0) {
    return (
      <div
        className={cn("p-6", className)}
        style={{
          background: "rgba(33, 32, 58, 0.6)",
          border: "0.667px solid #2c2a4a",
          borderRadius: 16,
        }}
      >
        <h3 className="text-sm font-semibold text-foreground mb-2">Available Prints</h3>
        <p className="text-sm text-muted-foreground">No print variants available.</p>
      </div>
    )
  }

  const visible = showAll ? prints : prints.slice(0, VISIBLE_DEFAULT)
  const hiddenCount = prints.length - VISIBLE_DEFAULT
  const effectivePrintId = currentPrintId ?? selectedPrint?.id

  return (
    <div
      className={cn("overflow-hidden", className)}
      style={{
        background: "rgba(33, 32, 58, 0.6)",
        border: "0.667px solid #2c2a4a",
        borderRadius: 16,
      }}
    >
      {/* Header */}
      <div className="flex items-center justify-between px-6 py-4" style={{ borderBottom: "1px solid rgba(44, 42, 74, 0.5)" }}>
        <span
          className="font-barlow font-semibold uppercase"
          style={{ fontSize: 14, letterSpacing: "0.84px", color: "var(--text-secondary, #B8B0D8)" }}
        >
          Printings
        </span>
        <span className="text-xs text-muted-foreground bg-muted px-2 py-0.5 rounded-full">
          {prints.length}
        </span>
      </div>

      {/* Printings table */}
      <div
        className="max-h-[320px] overflow-y-auto scrollbar-thin scrollbar-thumb-border scrollbar-track-transparent"
      >
        <table className="w-full" role="radiogroup" aria-label="Select card printing">
          <thead>
            <tr style={{ borderBottom: "1px solid rgba(44, 42, 74, 0.5)" }}>
              <th
                className="text-left pl-6 pr-3 py-2 font-semibold uppercase"
                style={{ fontSize: 11, letterSpacing: "0.66px", color: "#7b72a8" }}
              >
                Set
              </th>
              <th
                className="text-left px-3 py-2 font-semibold uppercase"
                style={{ fontSize: 11, letterSpacing: "0.66px", color: "#7b72a8" }}
              >
                Year
              </th>
              <th
                className="text-left px-3 py-2 font-semibold uppercase"
                style={{ fontSize: 11, letterSpacing: "0.66px", color: "#7b72a8" }}
              >
                Rarity
              </th>
              <th
                className="text-left px-3 py-2 font-semibold uppercase"
                style={{ fontSize: 11, letterSpacing: "0.66px", color: "#7b72a8" }}
              >
                Condition
              </th>
              <th
                className="text-right pl-3 pr-6 py-2 font-semibold uppercase"
                style={{ fontSize: 11, letterSpacing: "0.66px", color: "#7b72a8" }}
              >
                Market Price
              </th>
            </tr>
          </thead>
          <tbody>
            {visible.map((print, rowIndex) => {
              const isSelected = print.id === effectivePrintId
              const foil = isFoil(print)
              const hasSelection = visible.some((p) => p.id === effectivePrintId)

              return (
                <tr
                  key={print.id}
                  role="radio"
                  aria-checked={isSelected}
                  aria-label={`${print.set?.code || "???"} ${print.set?.name || "Unknown"}`}
                  tabIndex={isSelected || (!hasSelection && rowIndex === 0) ? 0 : -1}
                  onClick={() => onPrintSelect?.(print)}
                  onKeyDown={(e) => {
                    if (e.key === "Enter" || e.key === " ") {
                      e.preventDefault()
                      onPrintSelect?.(print)
                    } else if (e.key === "ArrowDown" || e.key === "ArrowUp") {
                      e.preventDefault()
                      const rows = Array.from(
                        e.currentTarget.parentElement?.querySelectorAll('[role="radio"]') ?? []
                      ) as HTMLTableRowElement[]
                      const currentIndex = rows.indexOf(e.currentTarget as HTMLTableRowElement)
                      if (currentIndex === -1) return
                      const delta = e.key === "ArrowDown" ? 1 : -1
                      const nextIndex = currentIndex + delta
                      if (nextIndex < 0 || nextIndex >= rows.length) return
                      rows[nextIndex].focus()
                      const nextPrint = visible[nextIndex]
                      if (nextPrint) onPrintSelect?.(nextPrint)
                    }
                  }}
                  className={cn(
                    "cursor-pointer transition-colors",
                    "hover:bg-muted/30",
                    "focus-visible:outline focus-visible:outline-2 focus-visible:outline-[#8b5cf6]",
                    isSelected
                      ? "border-l-2 border-l-[#8b5cf6]"
                      : "border-l-2 border-l-transparent"
                  )}
                  style={{
                    borderBottom: "1px solid rgba(44, 42, 74, 0.5)",
                    ...(isSelected ? { background: "rgba(139, 92, 246, 0.06)" } : {}),
                  }}
                >
                  <td className="pl-6 pr-3 py-2.5">
                    <span
                      className="font-bold"
                      style={{ fontSize: 13, color: isSelected ? "#f0eeff" : "#b8b0d8" }}
                    >
                      {print.set?.code || "???"}
                    </span>
                  </td>
                  <td className="px-3 py-2.5" style={{ fontSize: 13, color: "#b8b0d8" }}>
                    {getYear(print.set?.releaseDate)}
                  </td>
                  <td className="px-3 py-2.5 capitalize" style={{ fontSize: 13, color: "#b8b0d8" }}>
                    {print.rarity?.toLowerCase() || "—"}
                  </td>
                  <td className="px-3 py-2.5" style={{ fontSize: 13, color: "#b8b0d8" }}>
                    —
                  </td>
                  <td className="pl-3 pr-6 py-2.5 text-right">
                    {print.cheapestPrice !== undefined ? (
                      <span className="font-dm-mono" style={{ fontSize: 13, color: isSelected ? "#f0eeff" : "#b8b0d8" }}>
                        {formatPrice(print.cheapestPrice)}
                        {foil && (
                          <span
                            className="ml-1 text-[9px] px-1 py-px rounded font-semibold"
                            style={{
                              background: "linear-gradient(135deg, #a78bfa, #60a5fa, #34d399, #fcd34d)",
                              color: "#09090F",
                            }}
                          >
                            Foil
                          </span>
                        )}
                      </span>
                    ) : (
                      <span className="italic" style={{ color: "#7b72a8" }}>—</span>
                    )}
                  </td>
                </tr>
              )
            })}
          </tbody>
        </table>
      </div>

      {/* Footer: view all printings */}
      {!showAll && hiddenCount > 0 && (
        <div className="py-3 text-center" style={{ borderTop: "1px solid rgba(44, 42, 74, 0.5)" }}>
          <button
            onClick={() => setShowAll(true)}
            className="font-medium"
            style={{ fontSize: 13, color: "#8b5cf6" }}
          >
            View all {prints.length} printings &rarr;
          </button>
        </div>
      )}
      {showAll && prints.length > VISIBLE_DEFAULT && (
        <div className="py-3 text-center" style={{ borderTop: "1px solid rgba(44, 42, 74, 0.5)" }}>
          <button
            onClick={() => setShowAll(false)}
            className="font-medium"
            style={{ fontSize: 13, color: "#7b72a8" }}
          >
            Show less
          </button>
        </div>
      )}
    </div>
  )
}

