.glassCard {
  background: rgba(33, 32, 58, 0.60);
  backdrop-filter: blur(8px);
  -webkit-backdrop-filter: blur(8px);
  border: 1px solid var(--border-default, #2C2A4A);
  border-radius: 16px;
}

.glassCardStrong {
  background: rgba(33, 32, 58, 0.75);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  border: 1px solid var(--border-strong, #4A4680);
  border-radius: 16px;
}

/* =============================================
   MOBILE TABS
   ============================================= */
.mobileTabs {
  display: flex;
  border-bottom: 1px solid var(--border-default, #2C2A4A);
  padding: 0 16px;
}

.mobileTab {
  padding: 12px 16px;
  font-size: 13px;
  font-weight: 600;
  color: var(--text-tertiary, #7B72A8);
  border-bottom: 2px solid transparent;
  cursor: pointer;
  white-space: nowrap;
  background: none;
  border-top: none;
  border-left: none;
  border-right: none;
}

.mobileTab:hover {
  color: var(--text-secondary, #B8B0D8);
}

.mobileTabActive {
  color: var(--brand-primary, #8B5CF6);
  border-bottom-color: var(--brand-primary, #8B5CF6);
}

.mobileTabContent {
  padding: 16px;
}

/* =============================================
   RELATED CARDS
   ============================================= */
