  font-family: var(--font-display, 'Barlow Condensed', sans-serif);
  font-size: 24px;
  font-weight: 700;
  color: var(--text-primary, #F0EEFF);
  margin-bottom: 24px;
}

.relatedScroll {
  display: flex;
  gap: 16px;
  overflow-x: auto;
  padding-bottom: 8px;
}

.relatedCard {
  flex-shrink: 0;
  width: 150px;
  text-decoration: none;
}

.relatedCardImg {
  width: 150px;
  height: 210px;
  border-radius: 10px;
  background: var(--bg-surface-2, #21203A);
  border: 1px solid var(--border-default, #2C2A4A);
  overflow: hidden;
  position: relative;
  margin-bottom: 8px;
  transition: border-color 0.15s, box-shadow 0.15s;
}

.relatedCard:hover .relatedCardImg {
  border-color: var(--brand-primary, #8B5CF6);
  box-shadow: 0 0 20px rgba(139, 92, 246, 0.15);
}

.relatedCardName {
  font-size: 13px;
  font-weight: 600;
  color: var(--text-primary, #F0EEFF);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.relatedCardPrice {
  font-family: var(--font-mono, 'DM Mono', monospace);
  font-size: 13px;
  color: var(--text-secondary, #B8B0D8);
