"use client"

import Link from "next/link"
import { BlurHashImage } from "@/components/common/BlurHashImage"
import { getCardImageUrl } from "@/lib/data/cards"
import styles from "@/styles/card-detail.module.css"

export interface RelatedCard {
  id: string
  name: string
  /** Price in cents */
  price?: number
  /** Image URL — if not provided, falls back to placeholder */
  imageUrl?: string
  blurhash?: string
  /** URL slug or path for linking */
  href?: string
}

interface RelatedCardsProps {
  cards: RelatedCard[]
  /** Fallback when no related cards: link to browse same set */
  sameSetHref?: string
  sameSetName?: string
}

function formatPrice(cents: number): string {
  return `$${(cents / 100).toFixed(2)}`
}

export function RelatedCards({ cards, sameSetHref, sameSetName }: RelatedCardsProps) {
  if (cards.length === 0) {
    if (sameSetHref && sameSetName) {
      return (
        <div className={styles.relatedSection} data-testid="related-cards">
          <h2 className={styles.relatedTitle}>You Might Also Like</h2>
          <p style={{ fontSize: 14, color: "var(--text-secondary, #B8B0D8)" }}>
            Browse more cards from{" "}
            <Link
              href={sameSetHref}
              style={{ color: "var(--brand-primary, #8B5CF6)" }}
              data-testid="same-set-link"
            >
              {sameSetName}
            </Link>
          </p>
        </div>
      )
    }
    return null
  }

  return (
    <div className={styles.relatedSection} data-testid="related-cards">
      <h2 className={styles.relatedTitle}>You Might Also Like</h2>
      <div className={styles.relatedScroll} data-testid="related-cards-scroll">
        {cards.map((card) => (
          <Link
            key={card.id}
            href={card.href || `/cards/${card.id}`}
            className={styles.relatedCard}
            data-testid={`related-card-${card.id}`}
          >
            <div className={styles.relatedCardImg}>
              {card.imageUrl ? (
                <BlurHashImage
                  src={card.imageUrl}
                  alt={card.name}
                  blurhash={card.blurhash}
                  fill
                  sizes="(max-width: 768px) 110px, 150px"
                  className="object-contain"
                />
              ) : (
                <span
                  style={{
                    fontSize: 11,
                    color: "var(--text-tertiary, #7B72A8)",
                    textAlign: "center",
                    padding: 8,
                  }}
                >
                  {card.name}
                </span>
              )}
            </div>
            <div className={styles.relatedCardName}>{card.name}</div>
            {card.price !== undefined && (
              <div className={styles.relatedCardPrice}>{formatPrice(card.price)}</div>
            )}
          </Link>
        ))}
      </div>
    </div>
  )
}

