/**
 * @vitest-environment jsdom
 */
import React from "react"
import { render, screen } from "@testing-library/react"
import { describe, it, expect, vi } from "vitest"

vi.mock("next/link", () => ({
  default: ({ children, href, ...props }: { children: React.ReactNode; href: string; [key: string]: unknown }) => (
    <a href={href} {...props}>{children}</a>
  ),
}))

vi.mock("next/image", () => ({
  default: ({ src, alt }: { src: string; alt: string }) => <img src={src} alt={alt} />,
}))

vi.mock("@/components/common/BlurHashImage", () => ({
  BlurHashImage: ({ src, alt }: { src: string; alt: string }) => <img src={src} alt={alt} />,
}))

vi.mock("@/lib/data/cards", () => ({
  getCardImageUrl: () => "https://example.com/card.jpg",
}))

vi.mock("@/styles/card-detail.module.css", () => ({
  default: {
    relatedSection: "relatedSection",
    relatedTitle: "relatedTitle",
    relatedScroll: "relatedScroll",
    relatedCard: "relatedCard",
    relatedCardImg: "relatedCardImg",
    relatedCardName: "relatedCardName",
    relatedCardPrice: "relatedCardPrice",
  },
}))

import { RelatedCards, type RelatedCard } from "../RelatedCards"

const makeRelatedCard = (overrides: Partial<RelatedCard> = {}): RelatedCard => ({
  id: "card-1",
  name: "Chain Lightning",
  price: 349,
  imageUrl: "https://example.com/chain-lightning.jpg",
  ...overrides,
})

describe("RelatedCards", () => {
  it("renders nothing when no cards and no same-set fallback", () => {
    const { container } = render(<RelatedCards cards={[]} />)
    expect(container.innerHTML).toBe("")
  })

  it("renders same-set link fallback when no cards but set info provided", () => {
    render(
      <RelatedCards
        cards={[]}
        sameSetHref="/cards?set=3ED"
        sameSetName="Revised Edition"
      />
    )
    expect(screen.getByTestId("related-cards")).toBeDefined()
    expect(screen.getByText("You Might Also Like")).toBeDefined()
    const link = screen.getByTestId("same-set-link")
    expect(link.getAttribute("href")).toBe("/cards?set=3ED")
    expect(link.textContent).toBe("Revised Edition")
  })

  it("renders related cards in a horizontal scroll container", () => {
    const cards = [
      makeRelatedCard({ id: "c1", name: "Chain Lightning" }),
      makeRelatedCard({ id: "c2", name: "Shock", price: 15 }),
      makeRelatedCard({ id: "c3", name: "Rift Bolt", price: 49 }),
    ]
    render(<RelatedCards cards={cards} />)

    expect(screen.getByTestId("related-cards")).toBeDefined()
    expect(screen.getByTestId("related-cards-scroll")).toBeDefined()
    expect(screen.getByText("You Might Also Like")).toBeDefined()
  })

  it("renders each card with name and formatted price", () => {
    const cards = [
      makeRelatedCard({ id: "c1", name: "Chain Lightning", price: 349 }),
      makeRelatedCard({ id: "c2", name: "Shock", price: 15 }),
    ]
    render(<RelatedCards cards={cards} />)

    expect(screen.getByText("Chain Lightning")).toBeDefined()
    expect(screen.getByText("$3.49")).toBeDefined()
    expect(screen.getByText("Shock")).toBeDefined()
    expect(screen.getByText("$0.15")).toBeDefined()
  })

  it("links each card to its detail page", () => {
    const cards = [
      makeRelatedCard({ id: "c1", name: "Chain Lightning" }),
      makeRelatedCard({ id: "c2", name: "Shock", href: "/cards/custom-slug" }),
    ]
    render(<RelatedCards cards={cards} />)

    const card1Link = screen.getByTestId("related-card-c1")
    expect(card1Link.getAttribute("href")).toBe("/cards/c1")

    const card2Link = screen.getByTestId("related-card-c2")
    expect(card2Link.getAttribute("href")).toBe("/cards/custom-slug")
  })

  it("renders card image when imageUrl is provided", () => {
    const cards = [
      makeRelatedCard({ id: "c1", name: "Chain Lightning", imageUrl: "https://example.com/cl.jpg" }),
    ]
    render(<RelatedCards cards={cards} />)

    expect(screen.getByAltText("Chain Lightning")).toBeDefined()
  })

  it("renders placeholder text when no imageUrl", () => {
    const cards = [
      makeRelatedCard({ id: "c1", name: "Chain Lightning", imageUrl: undefined }),
    ]
    render(<RelatedCards cards={cards} />)

    // The card name appears as placeholder inside the image container
    const cardElements = screen.getAllByText("Chain Lightning")
    expect(cardElements.length).toBeGreaterThanOrEqual(2) // one placeholder + one label
  })

  it("omits price when not provided", () => {
    const cards = [
      makeRelatedCard({ id: "c1", name: "Chain Lightning", price: undefined }),
    ]
    render(<RelatedCards cards={cards} />)

    expect(screen.queryByText(/\$/)).toBeNull()
  })

  it("renders up to 8 cards", () => {
    const cards = Array.from({ length: 8 }, (_, i) =>
      makeRelatedCard({ id: `c${i}`, name: `Card ${i}` })
    )
    render(<RelatedCards cards={cards} />)

    cards.forEach((card) => {
      expect(screen.getByTestId(`related-card-${card.id}`)).toBeDefined()
    })
  })
})

